INPUT = '/app/spreadsheets/1_22-47_input.xlsx'
OUTPUT = '/app/output/1_22-47_output.xlsx'

wb = openpyxl.load_workbook(INPUT)
ws = wb['sheet1']

max_row = ws.max_row

# Collect data rows from A:C, skipping headers and empty rows
rows = []
seen = set()
for r in range(1, max_row + 1):
    a = ws.cell(row=r, column=1).value
    b = ws.cell(row=r, column=2).value
    c = ws.cell(row=r, column=3).value
    # skip header rows (where A == 'ITEM' or B == 'NAME' etc.)
    if isinstance(a, str) and a.strip().upper() == 'ITEM':
        continue
    if isinstance(b, str) and b.strip().upper() == 'NAME':
        continue
    # skip completely empty (in terms of B and C)
    if b is None and c is None:
        continue
    # need B value to consider
    if b is None:
        continue
    key = (b, c)
    if key in seen:
        continue
    seen.add(key)
    rows.append((b, c))

# Collect J list (helper column), preserving order, skip empty
j_list = []
for r in range(2, max_row + 1):
    v = ws.cell(row=r, column=10).value
    if v is None:
        continue
    if isinstance(v, str) and v.strip() == '':
        continue
    j_list.append(v)

# Sort: names in J first (in J's order), all matching rows in source order;
# then names not in J in source order.
if j_list:
    sorted_rows = []
    used_indices = set()
    for name in j_list:
        for i, (b, c) in enumerate(rows):
            if i in used_indices:
                continue
            if b == name:
                sorted_rows.append((b, c))
                used_indices.add(i)
    # add the rest in original order
    for i, (b, c) in enumerate(rows):
        if i not in used_indices:
            sorted_rows.append((b, c))
else:
    # alphabetical A-Z
    sorted_rows = sorted(rows, key=lambda x: (str(x[0]).upper()))

# Write to F2:H20
# Clear F2:H20 first
for r in range(2, 21):
    for col in [6, 7, 8]:
        ws.cell(row=r, column=col).value = None

# Write
for idx, (b, c) in enumerate(sorted_rows, start=1):
    row = 1 + idx  # F2 starts
    if row > 20:
        break
    ws.cell(row=row, column=6).value = idx
    ws.cell(row=row, column=7).value = b
    ws.cell(row=row, column=8).value = c

wb.save(OUTPUT)
print('Saved to', OUTPUT)

# Print result
for r in range(1, 21):
    f = ws.cell(row=r, column=6).value
    g = ws.cell(row=r, column=7).value
    h = ws.cell(row=r, column=8).value
    print(f'Row {r}: F={f!r}, G={g!r}, H={h!r}')
